 55→        .ok()
 56→        .and_then(|meta_content| {
 57→            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
 58→            let sessions = meta.get("sessions")?.as_array()?;
 59→            let session = sessions.get(session_index as usize)?;
