355→#[tauri::command]
356→fn watch_repo(
357→    repo_path: String,
358→    app: tauri::AppHandle,
359→    state: State<'_, Mutex<AppState>>,
360→) -> Result<(), String> {
361→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
362→
363→    // Don't double-watch
364→    if app_state.watched_repos.contains(&repo_path) {
365→        return Ok(());
366→    }
367→    app_state.watched_repos.insert(repo_path.clone());
368→
369→    let app_handle = app.clone();
370→    let repo_path_for_closure = repo_path.clone();
371→    watcher::watch_repo(&repo_path, move |event| {
372→        let event_name = match event {
373→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
374→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
375→            watcher::WatchEvent::ConfigChanged => "config-changed",
376→        };
377→        let _ = app_handle.emit(event_name, serde_json::json!({
378→            "repoPath": repo_path_for_closure,
379→        }));
380→    })?;
381→
382→    Ok(())
383→}
