  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { TitleBar } from "./components/TitleBar";
  5→import { TabBar } from "./components/TabBar";
  6→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  7→import { TranscriptView } from "./features/transcripts/TranscriptView";
  8→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
  9→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 10→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 11→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 12→import type { TerminalPanelHandle, TermSession } from "./features/terminal/TerminalPanel";
 13→import { useLiveUpdates } from "./hooks/use-live-updates";
 14→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 15→import { ArrowLeft, GitCommit } from "lucide-react";
 16→
 17→export interface Tab {
 18→  id: string;
 19→  branch: string;
 20→  repoPath: string;
 21→  worktree: WorktreeInfo | null;
 22→  hasActiveSession: boolean;
 23→}
 24→
 25→export default function App() {
 26→  const [tabs, setTabs] = useState<Tab[]>([
 27→    {
 28→      id: "main",
 29→      branch: "main",
 30→      repoPath: "",
 31→      worktree: null,
 32→      hasActiveSession: false,
 33→    },
 34→  ]);
 35→  const [activeTabId, setActiveTabId] = useState("main");
 36→  const [terminalHeight, setTerminalHeight] = useState(
 37→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 38→  );
 39→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 40→    () => localStorage.getItem("entire:terminal-open") !== "false"
 41→  );
 42→  const [innerTab, setInnerTab] = useState<
 43→    "checkpoints" | "diff" | "insights"
 44→  >("checkpoints");
 45→  const [selectedCheckpoint, setSelectedCheckpoint] =
 46→    useState<CheckpointSummary | null>(null);
 47→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 48→    "transcript" | "diff" | "insights"
 49→  >("transcript");
 50→
 51→  // Per-branch terminal sessions
 52→  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
 53→    () => new Map()
 54→  );
 55→
 56→  const terminalRef = useRef<TerminalPanelHandle>(null);
 57→
 58→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 59→  const activeSession = sessionMap.get(activeTabId) ?? null;
 60→
 61→  // Live updates — watch active repo for checkpoint/session changes
 62→  useLiveUpdates(activeTab.repoPath);
 63→
 64→  const handleSessionChange = useCallback(
 65→    (session: TermSession | null) => {
 66→      setSessionMap((prev) => {
 67→        const next = new Map(prev);
 68→        if (session) {
 69→          next.set(activeTabId, session);
 70→        } else {
 71→          next.delete(activeTabId);
 72→        }
 73→        return next;
 74→      });
 75→    },
 76→    [activeTabId]
 77→  );
 78→
 79→  // Agent dispatch — launch external Ghostty window
 80→  const handleSendToAgent = useCallback(
 81→    (agent: string, prompt: string) => {
 82→      invoke("launch_ghostty_agent", {
 83→        repoPath: activeTab.repoPath,
 84→        agent,
 85→        prompt,
 86→      }).catch((err: unknown) => {
 87→        console.error("Failed to launch external agent:", err);
 88→        // Fallback: open in embedded terminal
 89→        if (!isTerminalOpen) setIsTerminalOpen(true);
 90→        setTimeout(() => {
 91→          terminalRef.current?.launchAgentWithPrompt(agent, prompt);
 92→        }, isTerminalOpen ? 0 : 100);
 93→      });
 94→    },
 95→    [activeTab.repoPath, isTerminalOpen]
 96→  );
 97→
 98→  // Persist UI state to localStorage
 99→  useEffect(() => {
100→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
101→  }, [terminalHeight]);
102→  useEffect(() => {
103→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
104→  }, [isTerminalOpen]);
105→
106→  // Clear selected checkpoint when switching branch tabs
107→  useEffect(() => {
108→    setSelectedCheckpoint(null);
109→    setCheckpointInnerTab("transcript");
110→  }, [activeTabId]);
111→
112→  // Keyboard shortcuts
113→  useEffect(() => {
114→    function onKeyDown(e: KeyboardEvent) {
115→      const meta = e.metaKey || e.ctrlKey;
116→
117→      // Cmd+K = focus search
118→      if (meta && e.key === "k") {
119→        e.preventDefault();
120→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
121→      }
122→      // Ctrl+` = toggle terminal
123→      if (e.ctrlKey && e.key === "`") {
124→        e.preventDefault();
125→        setIsTerminalOpen((v) => !v);
126→      }
127→      // Cmd+W = close active tab
128→      if (meta && e.key === "w") {
129→        e.preventDefault();
130→        handleCloseTab(activeTabId);
131→      }
132→      // Cmd+1-9 = switch to tab by index
133→      if (meta && e.key >= "1" && e.key <= "9") {
134→        e.preventDefault();
135→        const idx = parseInt(e.key) - 1;
136→        if (idx < tabs.length) {
137→          setActiveTabId(tabs[idx].id);
138→        }
139→      }
140→      // Cmd+[ / Cmd+] = prev/next tab
141→      if (meta && e.key === "[") {
142→        e.preventDefault();
143→        const idx = tabs.findIndex((t) => t.id === activeTabId);
144→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
145→      }
146→      if (meta && e.key === "]") {
147→        e.preventDefault();
148→        const idx = tabs.findIndex((t) => t.id === activeTabId);
149→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
150→      }
151→      // Escape = deselect checkpoint
152→      if (e.key === "Escape" && selectedCheckpoint) {
153→        setSelectedCheckpoint(null);
154→      }
155→    }
156→    window.addEventListener("keydown", onKeyDown);
157→    return () => window.removeEventListener("keydown", onKeyDown);
158→  }, [activeTabId, tabs, selectedCheckpoint]);
159→
160→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
161→    const existing = tabs.find(
162→      (t) => t.branch === branch.name && t.repoPath === repoPath
163→    );
164→    if (existing) {
165→      setActiveTabId(existing.id);
166→    } else {
167→      const newTab: Tab = {
168→        id: `${repoPath}:${branch.name}`,
169→        branch: branch.name,
170→        repoPath,
171→        worktree: null,
172→        hasActiveSession: false,
173→      };
174→      setTabs([...tabs, newTab]);
175→      setActiveTabId(newTab.id);
176→    }
177→  }
178→
179→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
180→    const existing = tabs.find(
181→      (t) => t.branch === wt.branch && t.repoPath === repoPath
182→    );
183→    if (existing) {
184→      setActiveTabId(existing.id);
185→    } else {
186→      const newTab: Tab = {
187→        id: `${repoPath}:${wt.branch}`,
188→        branch: wt.branch,
189→        repoPath,
190→        worktree: wt,
191→        hasActiveSession: false,
192→      };
193→      setTabs([...tabs, newTab]);
194→      setActiveTabId(newTab.id);
195→    }
196→  }
197→
198→  function handleCloseTab(tabId: string) {
199→    if (tabs.length <= 1) return;
200→    const idx = tabs.findIndex((t) => t.id === tabId);
201→    const newTabs = tabs.filter((t) => t.id !== tabId);
202→    setTabs(newTabs);
203→    if (activeTabId === tabId) {
204→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
205→    }
206→    // Clean up session for closed tab
207→    setSessionMap((prev) => {
208→      const next = new Map(prev);
209→      next.delete(tabId);
210→      return next;
211→    });
212→  }
213→
214→  function handleResizeStart(e: React.MouseEvent) {
215→    e.preventDefault();
216→    const startY = e.clientY;
217→    const startHeight = terminalHeight;
218→
219→    function onMouseMove(ev: MouseEvent) {
220→      const delta = startY - ev.clientY;
221→      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
222→    }
223→    function onMouseUp() {
224→      window.removeEventListener("mousemove", onMouseMove);
225→      window.removeEventListener("mouseup", onMouseUp);
226→    }
227→    window.addEventListener("mousemove", onMouseMove);
228→    window.addEventListener("mouseup", onMouseUp);
229→  }
230→
231→  const repoName = activeTab.repoPath
232→    ? activeTab.repoPath.split("/").pop()
233→    : "";
234→
235→  return (
236→    <div className="flex h-screen flex-col">
237→      <TitleBar
238→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
239→      />
240→
241→      <div className="flex flex-1 overflow-hidden">
242→        {/* Sidebar */}
243→        <Sidebar
244→          activeTab={activeTab}
245→          onBranchSelect={handleBranchSelect}
246→          onWorktreeSelect={handleWorktreeSelect}
247→        />
248→
249→        {/* Main content */}
250→        <div className="flex flex-1 flex-col overflow-hidden">
251→          <TabBar
252→            tabs={tabs}
253→            activeTabId={activeTabId}
254→            onSelectTab={setActiveTabId}
255→            onCloseTab={handleCloseTab}
256→          />
257→
258→          <div className="flex flex-1 flex-col overflow-hidden">
259→            {/* Inner tabs */}
260→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
261→              {(["checkpoints", "diff", "insights"] as const).map((tab) => (
262→                <button
263→                  key={tab}
264→                  onClick={() => setInnerTab(tab)}
265→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
266→                    innerTab === tab
267→                      ? "border-accent text-fg"
268→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
269→                  }`}
270→                >
271→                  {tab === "checkpoints"
272→                    ? "Checkpoints"
273→                    : tab === "diff"
274→                      ? "Diff"
275→                      : "Insights"}
276→                </button>
277→              ))}
278→            </div>
279→
280→            {/* Main view */}
281→            <div className="flex flex-1 overflow-hidden bg-bg">
282→              {innerTab === "checkpoints" && (
283→                <>
284→                  {/* Checkpoint list — always visible when on checkpoints tab */}
285→                  <div
286→                    className={`overflow-y-auto ${
287→                      selectedCheckpoint
288→                        ? "w-[320px] shrink-0 border-r border-border-subtle"
289→                        : "flex-1"
290→                    }`}
291→                  >
292→                    <CheckpointList
293→                      repoPath={activeTab.repoPath}
294→                      branch={activeTab.branch}
295→                      onSelectCheckpoint={(cp) => {
296→                        setSelectedCheckpoint(cp);
297→                        setCheckpointInnerTab("transcript");
298→                      }}
299→                    />
300→                  </div>
301→
302→                  {/* Checkpoint detail panel */}
303→                  {selectedCheckpoint && (
304→                    <div className="flex flex-1 flex-col overflow-hidden">
305→                      {/* Detail header */}
306→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
307→                        <button
308→                          onClick={() => setSelectedCheckpoint(null)}
309→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
310→                        >
311→                          <ArrowLeft size={14} />
312→                        </button>
313→                        <GitCommit size={14} className="text-fg-subtle" />
