  1→import { useState, useMemo } from "react";
  2→import { Loader2, User, Bot, Wrench, ChevronDown, ChevronRight } from "lucide-react";
  3→import ReactMarkdown from "react-markdown";
  4→import remarkGfm from "remark-gfm";
  5→import { useTranscriptQuery } from "../../hooks/use-tauri-query";
  6→import type { CheckpointSummary } from "../../lib/ipc";
  7→
  8→interface TranscriptViewProps {
  9→  repoPath: string;
 10→  checkpoint: CheckpointSummary | null;
 11→}
 12→
 13→function isJsonString(text: string): boolean {
 14→  const trimmed = text.trim();
 15→  if (
 16→    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
 17→    (trimmed.startsWith("[") && trimmed.endsWith("]"))
 18→  ) {
 19→    try {
 20→      JSON.parse(trimmed);
 21→      return true;
 22→    } catch {
 23→      return false;
 24→    }
 25→  }
 26→  return false;
 27→}
 28→
 29→/** Tokenize JSON string into colored spans using React elements */
 30→function JsonHighlight({ json }: { json: string }) {
 31→  const tokens: React.ReactNode[] = [];
 32→  const regex = /("(?:\\.|[^"\\])*")|(true|false|null)|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|([{}[\]:,])|(\s+)/g;
 33→  let match: RegExpExecArray | null;
 34→  let lastIndex = 0;
 35→  let keyIndex = 0;
 36→
 37→  const jsonStr = json;
 38→  while ((match = regex.exec(jsonStr)) !== null) {
 39→    if (match.index > lastIndex) {
 40→      tokens.push(jsonStr.slice(lastIndex, match.index));
 41→    }
 42→    const [, str, bool, num, punct, ws] = match;
 43→    if (str) {
 44→      const after = jsonStr.slice(regex.lastIndex).match(/^\s*:/);
 45→      if (after) {
 46→        tokens.push(<span key={keyIndex++} className="text-blue">{str}</span>);
 47→      } else {
 48→        tokens.push(<span key={keyIndex++} className="text-green">{str}</span>);
 49→      }
 50→    } else if (bool) {
 51→      tokens.push(<span key={keyIndex++} className="text-yellow">{bool}</span>);
 52→    } else if (num) {
 53→      tokens.push(<span key={keyIndex++} className="text-accent-fg">{num}</span>);
 54→    } else if (punct) {
 55→      tokens.push(<span key={keyIndex++} className="text-fg-subtle">{punct}</span>);
 56→    } else if (ws) {
 57→      tokens.push(ws);
 58→    }
 59→    lastIndex = regex.lastIndex;
 60→  }
 61→  if (lastIndex < jsonStr.length) {
 62→    tokens.push(jsonStr.slice(lastIndex));
 63→  }
 64→
 65→  return <>{tokens}</>;
 66→}
 67→
 68→function JsonViewer({ text }: { text: string }) {
 69→  const formatted = useMemo(() => {
 70→    try {
 71→      return JSON.stringify(JSON.parse(text.trim()), null, 2);
 72→    } catch {
 73→      return text;
 74→    }
 75→  }, [text]);
 76→
 77→  const lines = formatted.split("\n");
 78→  const [collapsed, setCollapsed] = useState(lines.length > 12);
 79→  const preview = lines.slice(0, 6).join("\n");
 80→
 81→  return (
 82→    <div className="relative">
 83→      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs leading-relaxed">
 84→        {collapsed ? (
 85→          <>
 86→            <JsonHighlight json={preview} />
 87→            {lines.length > 6 && (
 88→              <span className="text-fg-faint">{"\n  ..."}</span>
 89→            )}
 90→          </>
 91→        ) : (
 92→          <JsonHighlight json={formatted} />
 93→        )}
 94→      </pre>
 95→      {lines.length > 12 && (
 96→        <button
 97→          onClick={() => setCollapsed(!collapsed)}
 98→          className="mt-1 flex items-center gap-1 text-[10px] text-accent-fg hover:text-accent"
 99→        >
100→          {collapsed ? <ChevronRight size={10} /> : <ChevronDown size={10} />}
101→          {collapsed ? `Show all (${lines.length} lines)` : "Collapse"}
102→        </button>
103→      )}
104→    </div>
105→  );
106→}
107→
108→function MarkdownContent({ content }: { content: string }) {
109→  return (
110→    <div className="prose-transcript">
111→      <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
112→    </div>
113→  );
114→}
115→
116→function MessageContent({ content, toolInput }: { content: string; toolInput: string | null }) {
117→  if (toolInput) {
118→    if (isJsonString(toolInput)) {
119→      return <JsonViewer text={toolInput} />;
120→    }
121→    return (
122→      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs text-fg-subtle">
123→        {toolInput}
124→      </pre>
125→    );
126→  }
127→
128→  if (isJsonString(content)) {
129→    return <JsonViewer text={content} />;
130→  }
131→
132→  return <MarkdownContent content={content} />;
133→}
134→
135→export function TranscriptView({ repoPath, checkpoint }: TranscriptViewProps) {
136→  const {
137→    data: messages,
138→    isLoading,
139→    error,
140→  } = useTranscriptQuery(
141→    repoPath,
142→    checkpoint?.checkpoint_id ?? "",
143→    0 // First session
144→  );
145→
146→  if (!checkpoint) {
147→    return (
148→      <div className="flex items-center justify-center p-20 text-fg-subtle">
149→        Select a checkpoint to view its transcript
150→      </div>
151→    );
152→  }
153→
154→  if (isLoading) {
155→    return (
156→      <div className="flex items-center justify-center p-20">
157→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
158→      </div>
159→    );
160→  }
161→
162→  if (error) {
163→    return (
164→      <div className="p-8">
165→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
166→          <p className="text-sm text-fg-muted">
167→            Transcript not available for this checkpoint
168→          </p>
169→          <p className="mt-1 text-xs text-fg-subtle">
170→            {error instanceof Error ? error.message : "Unknown error"}
171→          </p>
172→        </div>
173→      </div>
174→    );
175→  }
176→
177→  if (!messages || messages.length === 0) {
178→    return (
179→      <div className="p-8">
180→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
181→          <p className="text-sm text-fg-muted">No transcript data</p>
182→          <p className="mt-1 text-xs text-fg-subtle">
183→            This checkpoint may not have session data recorded
184→          </p>
185→        </div>
186→      </div>
187→    );
188→  }
