                            let _ = window.show();
                            let _ = window.set_focus();
                        }
                    }
                })
                .build(app)?;

            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            list_repos,
            list_checkpoints,
            get_transcript,
            get_checkpoint_diff,
            get_branch_diff,
            list_sessions,
            spawn_agent,
            pty_input,
            pty_resize,
            kill_pty,
            launch_ghostty_agent,
            list_trails,
            watch_repo,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

